FROM jsonb_to_recordset('[{"id": "cap-106-english-reading-passage-16", "exam_id": "cap", "subject_id": "sub-cap-english-reading", "paper_id": "cap-106-english-reading", "question_type": "reading_passage", "question_text": "(16-18)", "options": [], "correct_answer": 0, "correct_answer_json": null, "parent_question_id": null, "media": {"passage_text": "Do you have some books you don’t want?\nYour old love may be someone’s new favorite.\nBring one book to the Town Library & get another one home for free!\nWhen & How:\nMarch 2 - March 14        Bring one book for one book festival card.\nMarch 16 - March 31       Bring one card for one book you like to read.\nWhat books:\nAll kinds of books EXCEPT school books, comic books, and dictionaries.\nNotice:\nYour book must be in good shape, without any page missing.\nYour book must be clean, and nothing is written on it.\nWant to know more? Please call 1234-5678. (We are closed on Mondays.)\n-Town Library-", "kind_hint": "single"}, "source": "official", "source_meta": {"parser_version": "cap_v0.1", "merger_version": "cap_merger_v0.2", "parsed_at": "2026-04-25T19:26:38+00:00", "source_pdf_sha1": "bdb4f62524e6", "answer_pdf_sha1": "0fa526cf1539", "flags": [], "parse_confidence": null, "intro_line": "(16-18)", "child_qnums": [16, 17, 18]}, "is_active": true, "auto_gradable": false, "difficulty": 3, "explanation": null}, {"id": "cap-106-english-reading-passage-19", "exam_id": "cap", "subject_id": "sub-cap-english-reading", "paper_id": "cap-106-english-reading", "question_type": "reading_passage", "question_text": "(19-21)", "options": [], "correct_answer": 0, "correct_answer_json": null, "parent_question_id": null, "media": {"passage_text": "I had a horrendous experience last Saturday.\nThat day, my family went camping near a big\nlake. While my parents were preparing dinner, my\nbrother and I were playing by the lake. A dirty man\nappeared from somewhere, and his face was half\ncovered by his hair. He walked to us and asked for\nsome water.\nWhen I gave him water, the bag he carried dropped, and things inside fell out\non the grass. I saw a rope, a knife, and a baseball bat. The strangest thing was that\nthere were also a woman’s shoe and a ring, and I’m sure they were not his. The man\nquickly put all his things back in the bag and looked at us angrily. At that moment,\nthe picture of a man the police was looking for came to my mind. He was the crazy\nkiller! I was so afraid that I could not move at all.\nLuckily, before he could get any closer, my mom shouted from far away, and the\nman hurried off into the dark.\n while 當……之時", "kind_hint": "single"}, "source": "official", "source_meta": {"parser_version": "cap_v0.1", "merger_version": "cap_merger_v0.2", "parsed_at": "2026-04-25T19:26:38+00:00", "source_pdf_sha1": "bdb4f62524e6", "answer_pdf_sha1": "0fa526cf1539", "flags": [], "parse_confidence": null, "intro_line": "(19-21)", "child_qnums": [19, 20, 21]}, "is_active": true, "auto_gradable": false, "difficulty": 3, "explanation": null}, {"id": "cap-106-english-reading-passage-22", "exam_id": "cap", "subject_id": "sub-cap-english-reading", "paper_id": "cap-106-english-reading", "question_type": "reading_passage", "question_text": "(22-24)", "options": [], "correct_answer": 0, "correct_answer_json": null, "parent_question_id": null, "media": {"passage_text": "Ruth: I’ve got two tickets for a football game. The Lions vs. the Sharks, front-row\nseats, next Saturday. Interested? You can take Jessica to the game.\nNate: How did you get the tickets?! They were all sold out months ago!\nRuth: And a table for two at Leeds.\nNate: Leeds?! But I called them yesterday and they said they were all booked for the\nyear!\nRuth: Now it’s yours. You and Jessica can have a lovely dinner there after the game.\nNate: Wait a second. This is just not like you. What’s the catch?\nRuth: Well, you know this Friday I’m leaving for my vacation in London, and . . . .\nNate: And what?\nRuth: And I was thinking if Charlie could stay with you next week.\nNate: The whole week?!\nRuth: Please! I can’t just leave him in my apartment.\nNate: You know I hate that stupid dog! And he hates me too.\nRuth: Please! You’re my last hope.\nNate: I need to think about it.\nRuth: OK, but not too long.                                                book 訂位\n", "kind_hint": "single"}, "source": "official", "source_meta": {"parser_version": "cap_v0.1", "merger_version": "cap_merger_v0.2", "parsed_at": "2026-04-25T19:26:38+00:00", "source_pdf_sha1": "bdb4f62524e6", "answer_pdf_sha1": "0fa526cf1539", "flags": [], "parse_confidence": null, "intro_line": "(22-24)", "child_qnums": [22, 23, 24]}, "is_active": true, "auto_gradable": false, "difficulty": 3, "explanation": null}, {"id": "cap-106-english-reading-passage-25", "exam_id": "cap", "subject_id": "sub-cap-english-reading", "paper_id": "cap-106-english-reading", "question_type": "reading_passage", "question_text": "(25-26)", "options": [], "correct_answer": 0, "correct_answer_json": null, "parent_question_id": null, "media": {"passage_text": "When you need to see a doctor, surely you will want to see a good one. But there is one\nimportant thing you may never have thought about: Has your doctor rested enough?\nDoctors in our country often have to work 34 hours or longer without sleep. Most\nof them work 104 hours a week, and some even 150. (There are only 168 hours a\nweek!) One report said that a doctor who works such long hours cannot think more\nclearly than a drunk driver. Another found that doctors who sleep 5.8 fewer hours\nthan the week before might make 22% more serious mistakes. Surely no one wants\nto get in a car that is driven by a drunk driver. So, how safe would you feel when you\nare under the care of a tired doctor?\nSadly this problem has been around for a long time. There are no laws about it yet\nand hospital bosses don’t look like they care either. And that is why we doctors are\nasking you to join us on the street this Sunday. Fight together with us on the street so\nwe can fight better for your life in the hospital.\nTime: 1 p.m. May 2nd    Place: City Hospital Square\n drunk 酒醉的 law 法律", "kind_hint": "single"}, "source": "official", "source_meta": {"parser_version": "cap_v0.1", "merger_version": "cap_merger_v0.2", "parsed_at": "2026-04-25T19:26:38+00:00", "source_pdf_sha1": "bdb4f62524e6", "answer_pdf_sha1": "0fa526cf1539", "flags": [], "parse_confidence": null, "intro_line": "(25-26)", "child_qnums": [25, 26]}, "is_active": true, "auto_gradable": false, "difficulty": 3, "explanation": null}, {"id": "cap-106-english-reading-passage-27", "exam_id": "cap", "subject_id": "sub-cap-english-reading", "paper_id": "cap-106-english-reading", "question_type": "reading_passage", "question_text": "(27-28)", "options": [], "correct_answer": 0, "correct_answer_json": null, "parent_question_id": null, "media": {"passage_text": "Have you ever seen a pumpkin that looks like a nose or an apple that looks\nlike a funny face? They may not look great, but they taste just as good as\nthe pretty ones. These strange-looking fruit and vegetables are called\n“seconds.” About 20-40% of what farmers grow is not so beautiful. Sadly,\nthese “seconds” seldom arrive at your table, but often go straight into the\ntrash can. Why? It’s because supermarkets don’t want to buy them from\nfarmers—they believe their shoppers only love beautiful things. Because\nof these “seconds,” some farmers lose a lot of money.\nWonky Markt wishes to change this. We’re helping sell these “seconds.”\nFarmers can save them from the trash can, and you can get them at a lower\nprice.\n1. NT$250 a box.\n2. You can choose as many as six kinds of fruit\nand vegetables a box.\n4. No service charge if order is over NT$1,000.\nSend us photos of your delicious dishes that are made with our “seconds” to\noneandonly@wonkymarkt.com, and you may win our cookbook.\n service charge 手續費", "kind_hint": "single", "footnotes": [{"num": 3, "text": "Service charge: NT$50 a box."}]}, "source": "official", "source_meta": {"parser_version": "cap_v0.1", "merger_version": "cap_merger_v0.2", "parsed_at": "2026-04-25T19:26:38+00:00", "source_pdf_sha1": "bdb4f62524e6", "answer_pdf_sha1": "0fa526cf1539", "flags": [], "parse_confidence": null, "intro_line": "(27-28)", "child_qnums": [27, 28]}, "is_active": true, "auto_gradable": false, "difficulty": 3, "explanation": null}, {"id": "cap-106-english-reading-passage-29", "exam_id": "cap", "subject_id": "sub-cap-english-reading", "paper_id": "cap-106-english-reading", "question_type": "reading_passage", "question_text": "(29-30)", "options": [], "correct_answer": 0, "correct_answer_json": null, "parent_question_id": null, "media": {"passage_text": "Below is the news about Dashing Shuttle’s bus line changes.\n1. Great news for people who\nDashing Shuttle ♦ Map of bus lines\ntravel between Apple City and\nPeach City! From July 1, we\nhave three more buses to Peach\n2UDQJH\u0003,VODQG\n3HDFK\u0003&LW\\                                              City every day.\n2. A trip from Apple City to\n%HDQ\u00037RZQ               $SSOH\u0003&LW\\                      Lemon City or Berry City will\ntake less time. From July 1, you\ncan go from Apple City to each\n/HPRQ\u0003&LW\\                                              of the two cities without changing\nbuses.\n3. Dashing Shuttle is the first\nin the country to open a bus\nline between Apple City and\n0HORQ\u0003&LW\\         Orange Island. From July 1,\n%DQDQD\nour bus will take you to Orange\n7RZQ\nIsland every day!\n3DSD\\D                    4. Our bus line between Apple\n&LW\\\nCity and Grape Town will stop\n*XDYD\nrunning on June 30. From July 1,\n7RZQ\nchanging buses at Guava Town\n*UDSH                                                or Banana Town will be the\n%HUU\\    0DQJR\u0003,VODQG\n7RZQ\n&LW\\                          best way to travel.\n5. From July 1, our bus runs from\n(DFK\u0003\u0003\u0003\u0003\u0003\u0003\u0003\u0003\u0003\u0003\u0003\u0003\u0003\u0003\u0003PHDQV\u0003D\u0003GLIIHUHQW\u0003EXV\u0003OLQH\u0011\nApple City to Mango Island\nthree times a day. You don’t need\nto change buses at Melon City\nanymore.", "kind_hint": "single"}, "source": "official", "source_meta": {"parser_version": "cap_v0.1", "merger_version": "cap_merger_v0.2", "parsed_at": "2026-04-25T19:26:38+00:00", "source_pdf_sha1": "bdb4f62524e6", "answer_pdf_sha1": "0fa526cf1539", "flags": [], "parse_confidence": null, "intro_line": "(29-30)", "child_qnums": [29, 30]}, "is_active": true, "auto_gradable": false, "difficulty": 3, "explanation": null}, {"id": "cap-106-english-reading-passage-31", "exam_id": "cap", "subject_id": "sub-cap-english-reading", "paper_id": "cap-106-english-reading", "question_type": "reading_passage", "question_text": "(31-33)", "options": [], "correct_answer": 0, "correct_answer_json": null, "parent_question_id": null, "media": {"passage_text": "Cinema Times\nJune 5th, 2005\nThanks to globalization, we get to see movies from around the world. If\nanyone should feel most excited about globalization, it is US movie makers. A\nstudy in 2001 shows that, for every 100 people who go to the theater, 85 see US\nmovies. This may be good news for US movie makers, but not for those in other\ncountries.\nChart 1 shows the percentages (%) of US movies in five countries in 1984\nand in 2001; Chart 2 shows the percentages (%) of domestic movies in the five\ncountries in 1984 and in 2001. In Chart 1, we can see that US movies have been\npopular in foreign markets. In Chart 2, we can see that domestic movies in the\nfive countries are not doing well in their domestic market. The falling market\nfor domestic movies may be a serious problem, but there is something more\nimportant. When people welcome US movies with open arms, they in fact also\nsay yes to the American way of thinking. Some people in these countries worry\nthat what is lost may not just be their domestic market for domestic movies,\nbut also their own way of thinking that has been passed down from parents to\nchildren.\n globalization 全球化 domestic 當地的；國產的；本國的", "kind_hint": "single"}, "source": "official", "source_meta": {"parser_version": "cap_v0.1", "merger_version": "cap_merger_v0.2", "parsed_at": "2026-04-25T19:26:38+00:00", "source_pdf_sha1": "bdb4f62524e6", "answer_pdf_sha1": "0fa526cf1539", "flags": [], "parse_confidence": null, "intro_line": "(31-33)", "child_qnums": [31, 32, 33]}, "is_active": true, "auto_gradable": false, "difficulty": 3, "explanation": null}, {"id": "cap-106-english-reading-passage-34", "exam_id": "cap", "subject_id": "sub-cap-english-reading", "paper_id": "cap-106-english-reading", "question_type": "reading_passage", "question_text": "(34-37)", "options": [], "correct_answer": 0, "correct_answer_json": null, "parent_question_id": null, "media": {"passage_text": "Jerry Stevens has been unhappy these months. He   34   a proud businessman\nof a successful shaved ice shop. His highest sales numbers were 1,899 plates a\nweek; people called him “Ice King.” But all this changed when the cookie shop\nacross the street started selling ice cream cookies. It took away half of his business.\nAnd   35   when Dan, his dead sister’s only son, came to work for him.\nDan was a nice young man with a simple mind, too simple, maybe. He always\nlet people try some shaved ice for free, but he never learned to see when “some”\nbecame “too much.” Many people came, but few bought. When the sales did not\ngrow with the heat, Jerry started to worry. He wanted to send Dan home. But how\ncould he? Dan had no family except him.\nThen, one day,   36  . And it was from across the street. The cookie shop\n37   a clerk. For Jerry, it was a great chance to get Dan out of his store without\nsending him home. After taking the shopkeeper to several nice dinners, Jerry got\nDan the job.\nNow Jerry could finally try and save his store. And maybe Dan would help by\nsending him a few people who are\nthirsty from eating too many cookies.\n shaved ice 刨冰", "kind_hint": "single"}, "source": "official", "source_meta": {"parser_version": "cap_v0.1", "merger_version": "cap_merger_v0.2", "parsed_at": "2026-04-25T19:26:38+00:00", "source_pdf_sha1": "bdb4f62524e6", "answer_pdf_sha1": "0fa526cf1539", "flags": [], "parse_confidence": null, "intro_line": "(34-37)", "child_qnums": [34, 35, 36, 37]}, "is_active": true, "auto_gradable": false, "difficulty": 3, "explanation": null}, {"id": "cap-106-english-reading-passage-38", "exam_id": "cap", "subject_id": "sub-cap-english-reading", "paper_id": "cap-106-english-reading", "question_type": "reading_passage", "question_text": "(38-41)", "options": [], "correct_answer": 0, "correct_answer_json": null, "parent_question_id": null, "media": {"passage_text": "Englishman Robert Scott is known for leading two\ntrips to Antarctica. The first one made him a star; the\nsecond   38  .\nAfter his first successful trip, Scott decided to be the\nfirst person to stand on the South Pole. However,   39  .\nHe would be in a race with Roald Amundsen, from\nNorway. Both left their countries by ship in June of 1910\nand arrived in Antarctica in January of 1911.\nAbout ten months later, both teams started their trips down to the South\nPole.   40  . Amundsen’s team used dogs, and Scott’s team used horses. Because\nhorses weren’t good at traveling on snow, it took Scott’s team 77 days to arrive at\nthe South Pole. They got there on January 17, 1912, and were surprised to find that\nAmundsen was ahead of them. The news hit Scott very hard, but what he didn’t know\nwas that   41  . His team began their long trip home with broken hearts. After days\nof terrible weather and little food, Scott lost his men one after another, and he himself\nwas the last one to meet the end of his life. No one on his team lived to go back home\nand tell their story. It was only learned through Scott’s diary.", "kind_hint": "single"}, "source": "official", "source_meta": {"parser_version": "cap_v0.1", "merger_version": "cap_merger_v0.2", "parsed_at": "2026-04-25T19:26:38+00:00", "source_pdf_sha1": "bdb4f62524e6", "answer_pdf_sha1": "0fa526cf1539", "flags": [], "parse_confidence": null, "intro_line": "(38-41)", "child_qnums": [38, 39, 40, 41]}, "is_active": true, "auto_gradable": false, "difficulty": 3, "explanation": null}]'::jsonb) AS t(
